{{CSS|content=
@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;1,400&family=Special+Elite&family=VT323&family=Crimson+Pro:ital,wght@0,300;0,400;1,300;1,400&family=Share+Tech+Mono&display=swap');

.page-header__categories {
    display: none !important;
}

.credits-card {
    background-color: #000000;
    width: 100%;
    max-width: 720px;
    margin: 0 auto;
    padding: 48px 56px 40px 56px;
    box-sizing: border-box;
    font-family: 'Segoe UI', Helvetica, sans-serif;
    position: relative;
    display: table;
}

.credits-inner {
    display: table-row;
}

.credits-text-col {
    display: table-cell;
    vertical-align: middle;
    width: 60%;
    padding-right: 24px;
}

.credits-image-col {
    display: table-cell;
    vertical-align: middle;
    width: 40%;
    text-align: center;
}

.credits-label {
    color: #ffffff;
    font-size: 15px;
    font-weight: 400;
    letter-spacing: 0.04em;
    margin: 0 0 4px 0;
    line-height: 1.3;
}

.credits-name {
    color: #ffffff;
    font-size: 48px;
    font-weight: 700;
    letter-spacing: -0.01em;
    margin: 0 0 10px 0;
    line-height: 1.1;
}

.credits-divider {
    border: none;
    border-top: 2px solid #ffffff;
    margin: 0 0 18px 0;
    width: 88%;
}

.credits-label-2 {
    color: #ffffff;
    font-size: 15px;
    font-weight: 400;
    letter-spacing: 0.04em;
    margin: 0 0 4px 0;
    line-height: 1.3;
}

.credits-name-2 {
    color: #ffffff;
    font-size: 40px;
    font-weight: 300;
    letter-spacing: 0.01em;
    margin: 0;
    line-height: 1.2;
}

.credits-butterfly {
    width: 180px;
    height: auto;
    display: block;
    margin: 0 auto;
}

.credits-end {
    color: #ffffff;
    font-size: 15px;
    font-weight: 400;
    text-align: center;
    padding-top: 36px;
    letter-spacing: 0.08em;
    display: table-caption;
    caption-side: bottom;
}

.page__main {
    background: #060a10 !important;
    background-image: url("https://static.wikia.nocookie.net/backrooms/images/1/17/Darkcracky.jpeg/revision/latest?cb=20260517153141") !important;
    background-size: cover !important;
    background-attachment: fixed !important;
    background-blend-mode: multiply !important;
    min-height: 100vh !important;
    padding: 5 !important;
    max-width: 100% !important;
}

.page-header,
.page-header__title,
h1.page-header__title {
    font-family: 'Playfair Display', serif !important;
    color: #8ab4d4 !important;
    text-shadow: 0 0 40px rgba(60, 100, 180, 0.4) !important;
    letter-spacing: 0.08em !important;
    border-bottom: 1px solid rgba(100, 140, 200, 0.2) !important;
}

.bms-nav {
    display: flex;
    justify-content: center;
    gap: 0;
    padding: 1.2rem 0;
    border-bottom: 1px solid rgba(100, 140, 200, 0.18);
    background: rgba(6, 10, 16, 0.85);
    position: sticky;
    top: 0;
    z-index: 100;
    backdrop-filter: blur(8px);
}

.bms-nav-item {
    font-family: 'Share Tech Mono', monospace;
    font-size: 0.78rem;
    letter-spacing: 0.18em;
    text-transform: uppercase;
    color: #7aa0c4;
    padding: 0.5rem 1.6rem;
    border: 1px solid rgba(100, 140, 200, 0.2);
    text-decoration: none !important;
    transition: all 0.3s ease;
    cursor: pointer;
}

.bms-nav-item:first-child { border-right: none; }
.bms-nav-item:last-child { border-left: none; }

.bms-nav-item:hover {
    color: #c8dff0;
    background: rgba(100, 150, 220, 0.1);
    text-shadow: 0 0 12px rgba(120, 160, 220, 0.5);
}

.bms-section {
    position: relative;
    margin: 0;
    overflow: hidden;
}

.bms-section-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 1.4rem 3rem;
    border-bottom: 1px solid rgba(100, 140, 200, 0.15);
    transition: background 0.3s ease;
    user-select: none;
}

.bms-section-header:hover {
    background: rgba(80, 120, 200, 0.06);
}

.bms-section-header .bms-section-label {
    font-family: 'Share Tech Mono', monospace;
    font-size: 0.72rem;
    letter-spacing: 0.22em;
    text-transform: uppercase;
    color: #5a80a8;
}

.mw-collapsible-toggle {
    display: none !important;
}

.bms-narrative {
    background: rgba(6, 10, 18, 0.92);
    position: relative;
}

.bms-narrative::before {
    content: '';
    position: absolute;
    inset: 0;
    background: radial-gradient(ellipse at 20% 30%, rgba(30, 60, 120, 0.12) 0%, transparent 60%),
                radial-gradient(ellipse at 80% 70%, rgba(20, 40, 90, 0.1) 0%, transparent 60%);
    pointer-events: none;
}

.bms-narrative-inner {
    position: relative;
    max-width: 680px;
    margin: 0 auto;
    padding: 4rem 2rem 5rem;
}

.bms-narrative-inner .bms-butterfly-deco {
    position: absolute;
    right: -60px;
    top: 80px;
    width: 220px;
    opacity: 0.09;
    animation: bms-float 8s ease-in-out infinite;
    pointer-events: none;
}

.bms-narrative-inner .bms-butterfly-deco-2 {
    position: absolute;
    left: -80px;
    bottom: 120px;
    width: 160px;
    opacity: 0.06;
    animation: bms-float 11s ease-in-out infinite reverse;
    pointer-events: none;
}

.bms-narrative-inner .bms-slash-deco {
    display: block;
    width: 90px;
    opacity: 0.25;
    margin: 2.5rem auto;
    animation: bms-pulse-glow 4s ease-in-out infinite;
}

@keyframes bms-float {
    0%, 100% { transform: translateY(0) rotate(-3deg); }
    50% { transform: translateY(-18px) rotate(3deg); }
}

@keyframes bms-pulse-glow {
    0%, 100% { opacity: 0.25; filter: none; }
    50% { opacity: 0.45; filter: drop-shadow(0 0 8px rgba(180, 60, 60, 0.4)); }
}

.bms-poem-block {
    font-family: 'Crimson Pro', serif;
    font-size: 1.12rem;
    line-height: 2;
    color: #a8c4de;
    font-weight: 300;
    font-style: italic;
    white-space: pre-line;
    position: relative;
    z-index: 1;
}

.bms-poem-block.align-center { text-align: center; }
.bms-poem-block.align-right { text-align: right; }
.bms-poem-block.align-left { text-align: left; }

.bms-poem-block .bms-scream {
    font-style: normal;
    font-weight: 700;
    font-size: 1.3rem;
    color: #c8dff0;
    letter-spacing: 0.04em;
    display: block;
}

.bms-poem-block .bms-whisper {
    font-size: 0.88rem;
    color: #5a7a9a;
    letter-spacing: 0.1em;
}

.bms-poem-block .bms-staccato {
    display: block;
    letter-spacing: 0.3em;
    font-style: normal;
    color: #7a9ec0;
    font-size: 0.9rem;
}

.bms-ellipsis {
    display: block;
    text-align: center;
    color: #2a4060;
    font-size: 1.6rem;
    letter-spacing: 0.5em;
    padding: 1.2rem 0;
    font-family: 'Crimson Pro', serif;
}

.bms-rule {
    border: none;
    border-top: 1px solid rgba(80, 120, 180, 0.15);
    margin: 2.5rem 0;
    position: relative;
}

.bms-rule::after {
    content: '\2767';
    position: absolute;
    left: 50%;
    top: 50%;
    transform: translate(-50%, -50%);
    background: #060a10;
    padding: 0 0.8rem;
    color: rgba(80, 120, 180, 0.35);
    font-size: 1rem;
}

.bms-cascade-block {
    font-family: 'Crimson Pro', serif;
    font-size: 1.12rem;
    color: #a8c4de;
    font-style: italic;
    line-height: 1.2;
    text-align: center;
    padding: 1rem 0;
}

.bms-cascade-block span {
    display: block;
    animation: bms-cascade-drift 6s ease-in-out infinite;
}

.bms-cascade-block span:nth-child(odd) { animation-delay: 0.3s; }
.bms-cascade-block span:nth-child(3n) { animation-delay: 0.6s; }

@keyframes bms-cascade-drift {
    0%, 100% { transform: translateX(0); opacity: 1; }
    50% { transform: translateX(2px); opacity: 0.8; }
}

.bms-drug {
    position: relative;
    overflow: hidden;
}

.bms-drug-bg {
    position: absolute;
    inset: 0;
    background-image: url("https://static.wikia.nocookie.net/backrooms/images/a/a8/Imonhigh.gif/revision/latest?cb=20260517153140");
    background-size: cover;
    background-position: center;
    opacity: 0.18;
    animation: bms-bg-breathe 8s ease-in-out infinite;
    pointer-events: none;
    z-index: 0;
}

@keyframes bms-bg-breathe {
    0%, 100% { opacity: 0.18; transform: scale(1); }
    50% { opacity: 0.26; transform: scale(1.04); }
}

.bms-drug-inner {
    position: relative;
    z-index: 1;
    max-width: 720px;
    margin: 0 auto;
    padding: 4rem 2rem 5rem;
}

.bms-drug-wine {
    display: block;
    width: 160px;
    margin: 0 auto 2rem;
    opacity: 0.85;
    animation: bms-wine-tilt 5s ease-in-out infinite;
    filter: drop-shadow(0 0 20px rgba(180, 30, 60, 0.5));
}

@keyframes bms-wine-tilt {
    0%, 100% { transform: rotate(-4deg) translateY(0); }
    25% { transform: rotate(6deg) translateY(-8px); }
    75% { transform: rotate(-8deg) translateY(4px); }
}

.bms-drug-poem {
    font-family: 'VT323', monospace;
    font-size: 1.35rem;
    line-height: 1.7;
    white-space: pre-line;
    position: relative;
}

.bms-drug-poem.align-center { text-align: center; }
.bms-drug-poem.align-right { text-align: right; }
.bms-drug-poem.align-left { text-align: left; }

@keyframes bms-hue-rotate {
    0% { color: #ff4aff; text-shadow: 0 0 8px #ff4aff; }
    16% { color: #ff4a4a; text-shadow: 0 0 8px #ff4a4a; }
    33% { color: #ffcc00; text-shadow: 0 0 8px #ffcc00; }
    50% { color: #00ffcc; text-shadow: 0 0 8px #00ffcc; }
    66% { color: #4a9fff; text-shadow: 0 0 8px #4a9fff; }
    83% { color: #cc44ff; text-shadow: 0 0 8px #cc44ff; }
    100% { color: #ff4aff; text-shadow: 0 0 8px #ff4aff; }
}

.bms-drug-poem .bms-rainbow {
    animation: bms-hue-rotate 3s linear infinite;
    display: inline;
}

.bms-drug-poem .bms-shake {
    display: inline-block;
    animation: bms-shake 0.4s ease-in-out infinite;
    color: #fff;
}

@keyframes bms-shake {
    0%, 100% { transform: translate(0, 0) rotate(0); }
    20% { transform: translate(-2px, 1px) rotate(-1deg); }
    40% { transform: translate(2px, -1px) rotate(1deg); }
    60% { transform: translate(-1px, 2px) rotate(-0.5deg); }
    80% { transform: translate(1px, -2px) rotate(0.5deg); }
}

.bms-drug-poem .bms-dissolve {
    animation: bms-dissolve-text 4s ease-in-out infinite;
    display: inline;
}

@keyframes bms-dissolve-text {
    0%, 100% { opacity: 1; letter-spacing: normal; }
    50% { opacity: 0.5; letter-spacing: 0.3em; }
}

.bms-drug-poem .bms-melt {
    display: block;
    animation: bms-melt-text 7s ease-in-out infinite;
}

@keyframes bms-melt-text {
    0%, 100% { transform: skewX(0deg) scaleY(1); opacity: 1; }
    30% { transform: skewX(-3deg) scaleY(0.96); opacity: 0.8; }
    70% { transform: skewX(3deg) scaleY(1.04); opacity: 0.9; }
}

.bms-drug-poem .bms-glitch {
    display: inline;
    position: relative;
    animation: bms-glitch-main 3s infinite;
}

@keyframes bms-glitch-main {
    0%, 90%, 100% { transform: none; color: #e8f0ff; }
    91% { transform: translateX(-3px); color: #ff4466; }
    92% { transform: translateX(3px); color: #44ffcc; }
    93% { transform: translateX(0); color: #e8f0ff; }
    94% { transform: translateX(-1px) skewX(5deg); color: #ffee44; }
    95% { transform: none; color: #e8f0ff; }
}

.bms-drug-separator {
    display: block;
    text-align: center;
    font-family: 'VT323', monospace;
    font-size: 1.5rem;
    padding: 1rem 0;
    animation: bms-sep-color 4s linear infinite;
    letter-spacing: 0.2em;
}

@keyframes bms-sep-color {
    0%, 100% { color: #ff4aff; }
    33% { color: #00ffcc; }
    66% { color: #ffcc00; }
}

.bms-drug-cascade {
    font-family: 'VT323', monospace;
    font-size: 1.3rem;
    line-height: 1.15;
    text-align: center;
    padding: 0.5rem 0;
}

.bms-drug-cascade span {
    display: block;
    animation: bms-hue-rotate 3s linear infinite;
}

.bms-drug-cascade span:nth-child(2) { animation-delay: 0.3s; }
.bms-drug-cascade span:nth-child(3) { animation-delay: 0.6s; }
.bms-drug-cascade span:nth-child(4) { animation-delay: 0.9s; }
.bms-drug-cascade span:nth-child(5) { animation-delay: 1.2s; }
.bms-drug-cascade span:nth-child(6) { animation-delay: 1.5s; }
.bms-drug-cascade span:nth-child(7) { animation-delay: 1.8s; }
.bms-drug-cascade span:nth-child(8) { animation-delay: 2.1s; }
.bms-drug-cascade span:nth-child(9) { animation-delay: 2.4s; }
.bms-drug-cascade span:nth-child(10) { animation-delay: 2.7s; }
.bms-drug-cascade span:nth-child(11) { animation-delay: 3s; }
.bms-drug-cascade span:nth-child(12) { animation-delay: 3.3s; }

.bms-drug-ellipsis {
    display: block;
    text-align: center;
    font-size: 2rem;
    letter-spacing: 0.6em;
    padding: 1rem 0;
    font-family: 'VT323', monospace;
    animation: bms-hue-rotate 6s linear infinite;
}

.bms-ad {
    position: relative;
    background: #0a0a08;
}

.bms-ad-inner {
    position: relative;
    max-width: 700px;
    margin: 0 auto;
    padding: 3rem 2rem 5rem;
}

.bms-ad-paper {
    position: relative;
    background-image: url("https://static.wikia.nocookie.net/backrooms/images/7/79/Filedocumentretro.png/revision/latest?cb=20260517153138");
    background-size: cover;
    background-position: center;
    padding: 3rem 3.5rem;
    box-shadow: 0 8px 40px rgba(0,0,0,0.7), inset 0 0 60px rgba(0,0,0,0.2);
    border: 3px double #8a7a5a;
    transform: rotate(-0.4deg);
}

.bms-ad-paper::before {
    content: '';
    position: absolute;
    inset: 0;
    background: rgba(220, 200, 160, 0.55);
    pointer-events: none;
    mix-blend-mode: multiply;
}

.bms-ad-header {
    text-align: center;
    margin-bottom: 1.5rem;
    position: relative;
    z-index: 1;
}

.bms-ad-announce {
    font-family: 'Special Elite', cursive;
    font-size: 0.75rem;
    letter-spacing: 0.35em;
    text-transform: uppercase;
    color: #4a3a20;
    display: block;
    margin-bottom: 0.5rem;
    border-top: 2px solid #6a5530;
    border-bottom: 2px solid #6a5530;
    padding: 0.3rem 0;
}

.bms-ad-title-wrap {
    position: relative;
    display: inline-block;
    margin: 1rem 0;
}

.bms-ad-starburst {
    width: 220px;
    display: block;
    margin: 0 auto;
    animation: bms-starburst-pulse 2s ease-in-out infinite;
    position: relative;
    z-index: 1;
}

@keyframes bms-starburst-pulse {
    0%, 100% { transform: scale(1) rotate(-1deg); }
    50% { transform: scale(1.04) rotate(1deg); }
}

.bms-ad-brand {
    font-family: 'Special Elite', cursive;
    font-size: 2.8rem;
    color: #1a0a05;
    line-height: 1;
    display: block;
    text-align: center;
    letter-spacing: 0.05em;
    text-shadow: 3px 3px 0 rgba(80, 50, 10, 0.3);
    position: relative;
    z-index: 1;
    margin: 0.5rem 0;
}

.bms-ad-subtitle {
    font-family: 'Special Elite', cursive;
    font-size: 1rem;
    color: #3a2a10;
    text-align: center;
    display: block;
    letter-spacing: 0.12em;
    margin-bottom: 1.5rem;
    position: relative;
    z-index: 1;
}

.bms-ad-divider-stars {
    text-align: center;
    font-size: 1rem;
    color: #6a5530;
    letter-spacing: 0.5em;
    margin: 1rem 0;
    position: relative;
    z-index: 1;
}

.bms-ad-body {
    font-family: 'Special Elite', cursive;
    font-size: 0.92rem;
    line-height: 1.75;
    color: #2a1e0c;
    position: relative;
    z-index: 1;
    text-align: justify;
}

.bms-ad-body p {
    margin: 0.8rem 0;
}

.bms-ad-body .bms-ad-emphasis {
    font-size: 1.1rem;
    color: #8a0000;
    display: block;
    text-align: center;
    margin: 1rem 0;
    letter-spacing: 0.05em;
}

.bms-ad-body .bms-ad-cta {
    display: block;
    text-align: center;
    font-size: 1.4rem;
    color: #8a0000;
    margin: 1.5rem 0 0.5rem;
    letter-spacing: 0.08em;
    text-decoration: underline;
    animation: bms-ad-cta-blink 1.5s step-end infinite;
}

@keyframes bms-ad-cta-blink {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.6; }
}

.bms-ad-free {
    display: block;
    text-align: center;
    font-family: 'Special Elite', cursive;
    font-size: 0.85rem;
    color: #5a4020;
    font-style: italic;
    margin-bottom: 1.5rem;
}

.bms-ad-disclaimer {
    font-family: 'Share Tech Mono', monospace;
    font-size: 0.62rem;
    line-height: 1.5;
    color: #4a3a20;
    border-top: 1px solid #8a7a5a;
    padding-top: 0.8rem;
    margin-top: 1.5rem;
    position: relative;
    z-index: 1;
}

.bms-convo {
    background: rgba(5, 8, 15, 0.95);
    position: relative;
}

.bms-convo::before {
    content: '';
    position: absolute;
    inset: 0;
    background: radial-gradient(ellipse at 50% 0%, rgba(20, 50, 100, 0.1) 0%, transparent 70%);
    pointer-events: none;
}

.bms-convo-inner {
    max-width: 660px;
    margin: 0 auto;
    padding: 4rem 2rem 5rem;
    position: relative;
    z-index: 1;
}

.bms-convo-block {
    display: flex;
    flex-direction: column;
    gap: 0;
    margin: 0 0 0.3rem;
}

.bms-speech-line {
    font-family: 'Crimson Pro', serif;
    font-size: 1.05rem;
    line-height: 1.8;
    padding: 0.15rem 0;
    position: relative;
}

.bms-speech-line.speaker-dad {
    color: #6a90b8;
    padding-left: 1.4rem;
    border-left: 2px solid rgba(80, 120, 180, 0.25);
    font-style: normal;
}

.bms-speech-line.speaker-agatha {
    color: #9abcd4;
    padding-right: 1.4rem;
    border-right: 2px solid rgba(130, 170, 210, 0.25);
    text-align: right;
    font-style: italic;
}

.bms-speech-line.speaker-narration {
    color: #4a6a88;
    font-size: 0.9rem;
    text-align: center;
    font-style: italic;
    padding: 0.5rem 2rem;
    border: none;
}

.bms-speech-label {
    font-family: 'Share Tech Mono', monospace;
    font-size: 0.6rem;
    letter-spacing: 0.2em;
    text-transform: uppercase;
    display: block;
    margin-bottom: 0.1rem;
}

.bms-speech-line.speaker-dad .bms-speech-label { color: #3a5878; }
.bms-speech-line.speaker-agatha .bms-speech-label { color: #507898; text-align: right; }

.bms-convo-ellipsis {
    display: block;
    text-align: center;
    color: #1e3050;
    font-size: 1.4rem;
    letter-spacing: 0.5em;
    padding: 0.8rem 0;
    font-family: 'Crimson Pro', serif;
}

.bms-convo-poem {
    font-family: 'Crimson Pro', serif;
    font-size: 1.05rem;
    line-height: 1.85;
    color: #8aaec8;
    font-style: italic;
    white-space: pre-line;
    padding: 1.5rem 0;
    border-top: 1px solid rgba(60, 100, 160, 0.12);
    border-bottom: 1px solid rgba(60, 100, 160, 0.12);
    margin: 1.5rem 0;
}

.bms-convo-poem.align-center { text-align: center; }
.bms-convo-poem.align-right { text-align: right; }

.bms-section-title-narrative {
    background: rgba(6, 10, 18, 0.98);
    border-bottom: 1px solid rgba(60, 100, 160, 0.2);
    cursor: pointer;
}

.bms-section-title-drug {
    background: #060008;
    border-bottom: 1px solid rgba(150, 0, 150, 0.2);
    cursor: pointer;
}

.bms-section-title-drug .bms-section-label {
    animation: bms-hue-rotate 4s linear infinite;
    font-family: 'VT323', monospace !important;
    font-size: 1rem !important;
    letter-spacing: 0.3em !important;
}

.bms-section-title-ad {
    background: #0a0a08;
    border-bottom: 1px solid rgba(120, 100, 60, 0.3);
    cursor: pointer;
}

